import{_ as e,c as o,o as n,ae as r}from"./chunks/framework.Cqi9LMMK.js";const m=JSON.parse('{"title":"Customize","description":"","frontmatter":{"title":"Customize"},"headers":[],"relativePath":"options/customize.md","filePath":"options/customize.md"}'),a={name:"options/customize.md"};function s(i,t,d,l,g,h){return n(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="customize" tabindex="-1">Customize <a class="header-anchor" href="#customize" aria-label="Permalink to &quot;Customize&quot;">​</a></h1><p><strong>Options → General → Customize</strong> controls the main inspector look: theme, background media, and how it is displayed. You style the <strong>tool</strong>, not the site content.</p><hr><h2 id="extension-vs-standalone" tabindex="-1">Extension vs standalone <a class="header-anchor" href="#extension-vs-standalone" aria-label="Permalink to &quot;Extension vs standalone&quot;">​</a></h2><p>Fields (<strong>theme</strong>, <strong>file / URL</strong>, opacity, blur, noise, position, scale) match. What differs is <strong>where file bytes go</strong> and <strong>whether a total quota applies</strong>.</p><table tabindex="0"><thead><tr><th></th><th><strong>Extension (Chrome / Edge)</strong></th><th><strong>Standalone</strong></th></tr></thead><tbody><tr><td><strong>Where uploads live</strong></td><td>Media copies in extension <strong>IndexedDB</strong> (separate stores for wallpaper and saved files).</td><td>Media goes into the app’s <strong>unified local store</strong> (central quota).</td></tr><tr><td><strong>Size limit</strong></td><td>No app-enforced “N MB for media”; real cap is <strong>IndexedDB / storage quota</strong> for the extension profile.</td><td><strong>Hard 30 MB</strong> total for decorative media in standalone storage — saves are blocked if the new total would exceed (error like “Media limit exceeded”).</td></tr><tr><td><strong>Usage meter</strong></td><td>The <strong>X MB / 30 MB</strong> counter <strong>does not</strong> show in Customize.</td><td>Customize shows <strong>usage</strong> of the media store (<strong>MB of 30 MB</strong>) so you see remaining headroom.</td></tr></tbody></table><p><strong>URL backgrounds</strong> do not count like uploaded files in local quota, but for offline predictability local files within quota are often simpler (in standalone respect <strong>30 MB</strong> total).</p><hr><h2 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h2><p><strong>Dark / Light</strong> toggles inspector color scheme.</p><hr><h2 id="background-image" tabindex="-1">Background (Image) <a class="header-anchor" href="#background-image" aria-label="Permalink to &quot;Background (Image)&quot;">​</a></h2><p><strong>Image</strong> sets the panel background. Sources — <strong>File</strong> and <strong>Link</strong>:</p><ul><li><strong>File</strong> — local asset via <strong>Browse</strong> or previously saved copies (extension: IndexedDB; standalone: unified 30 MB store — table above). Presets: <a href="/docs/options/settings_management.html">Settings management</a>.</li><li><strong>Link</strong> — URL to media.</li></ul><p>Supported: <strong>still images</strong>, animated <strong>GIF</strong>, <strong>MP4</strong> video backgrounds.</p><hr><h2 id="background-rendering" tabindex="-1">Background rendering <a class="header-anchor" href="#background-rendering" aria-label="Permalink to &quot;Background rendering&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Control</th><th>Role</th></tr></thead><tbody><tr><td><strong>Image Opacity</strong></td><td>Background layer transparency vs UI chrome.</td></tr><tr><td><strong>Blur</strong></td><td>Blur strength.</td></tr><tr><td><strong>Noise Intensity / Opacity</strong></td><td>Grain overlay strength/visibility.</td></tr><tr><td><strong>Position (X / Y)</strong></td><td>Pan the image.</td></tr><tr><td><strong>Scale</strong></td><td>Zoom <strong>100–200%</strong>.</td></tr></tbody></table><p>Combined, you can keep background subtle or decorative without hurting readability.</p><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/docs/options/display_mode.html">Display modes</a></li><li><a href="/docs/options/settings_management.html">Settings management</a></li></ul>',22)])])}const u=e(a,[["render",s]]);export{m as __pageData,u as default};
